class Solution:
    def numberOfWays(self, startPos, endPos, k):
        MOD = 10**9 + 7
        d = abs(endPos - startPos)
        if d > k or (k - d) % 2 != 0:
            return 0
        # DP over net displacement from start; index offset by k so range is 0..2k
        offset = k
        cur = [0] * (2 * k + 1)
        cur[offset] = 1
        for _ in range(k):
            nxt = [0] * (2 * k + 1)
            for p in range(2 * k + 1):
                v = cur[p]
                if v:
                    if p - 1 >= 0:
                        nxt[p - 1] = (nxt[p - 1] + v) % MOD
                    if p + 1 <= 2 * k:
                        nxt[p + 1] = (nxt[p + 1] + v) % MOD
            cur = nxt
        return cur[offset + (endPos - startPos)] % MOD

