class Solution:
    def numberOfWays(self, startPos, endPos, k):
        MOD = 10**9 + 7
        d = abs(endPos - startPos)
        if d > k or (k - d) % 2 != 0:
            return 0
        r = (k + d) // 2
        num = 1
        for i in range(r):
            num = num * (k - i) % MOD
        den = 1
        for i in range(1, r + 1):
            den = den * i % MOD
        return num * pow(den, MOD - 2, MOD) % MOD

