var numberOfWays = function(startPos, endPos, k) {
    const MOD = 1000000007n;
    const d = Math.abs(endPos - startPos);
    if (d > k || (k - d) % 2 !== 0) return 0;
    const r = (k + d) / 2;
    let num = 1n;
    for (let i = 0; i < r; i++) num = (num * BigInt(k - i)) % MOD;
    let den = 1n;
    for (let i = 1; i <= r; i++) den = (den * BigInt(i)) % MOD;
    let exp = MOD - 2n;
    let base = den % MOD;
    let inv = 1n;
    while (exp > 0n) {
        if (exp & 1n) inv = (inv * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1n;
    }
    return Number((num * inv) % MOD);
};
